import { describe, it, expect } from "vitest";
import { nextGeneration, type Cell } from "./game-of-life.js";

describe("Conway's Game of Life - nextGeneration", () => {
  it.todo("should return an empty array for an empty input");
  it.todo("should return an empty array for a single live cell (underpopulation)");
  it.todo("should return an empty array for two adjacent live cells (underpopulation)");
  it.todo("should keep a 2x2 block unchanged (still life)");
  it.todo("should transform a vertical blinker into a horizontal blinker");
  it.todo("should kill the center cell of a 3x3 full block (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
});
